1	export type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	export type Damage = { itemType: string; amount: number };
3	export type Incident = { cause: string; damages: Damage[] };
4	export type QuoteStep = { op: "quote"; items: Item[] };
5	export type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	export type Step = QuoteStep | ClaimStep;
7	export type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
8	export type QuoteResult = { premium: number };
9	export type ClaimResult = { payout: number; remainingCap: number };
10	export type ScenarioResult = { results: Array<QuoteResult | ClaimResult> };
11	
12	const PROCESSING_FEE = 5;
13	const FIRST_INSURANCE_RATE = 0.1;
14	const CURSE_SURCHARGE_RATE = 0.5;
15	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
16	const HIGH_ENCHANTMENT_THRESHOLD = 5;
17	const LOYALTY_DISCOUNT_RATE = 0.2;
18	const LOYALTY_THRESHOLD_YEARS = 2;
19	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
20	const DEDUCTIBLE = 100;
21	const CAP_MULTIPLIER = 2;
22	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
23	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
24	
25	type Customer = { yearsWithMHPCO: number };
26	const COMPONENT_UNIT_BASE = 25;
27	const COMPONENT_BLOCK_SIZE = 3;
28	const COMPONENT_BLOCK_BASE = 60;
29	
30	const MAIN_ITEM_BASE_PREMIUM: Record<string, number> = {
31	  sword: 100,
32	  amulet: 60,
33	  staff: 80,
34	  potion: 40,
35	};
36	
37	const ITEM_INSURANCE_VALUE: Record<string, number> = {
38	  sword: 1000,
39	  amulet: 600,
40	  staff: 800,
41	  potion: 400,
42	  rune: 250,
43	  moonstone: 250,
44	};
45	
46	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
47	
48	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
49	
50	type BillingGroup = { base: number; cursed: boolean; enchantment: number };
51	
52	const componentBundleBase = (count: number): number => {
53	  if (count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_BASE;
54	  return count * COMPONENT_UNIT_BASE;
55	};
56	
57	const billingGroups = (items: Item[]): BillingGroup[] => {
58	  const groups: BillingGroup[] = [];
59	  const componentCounts = new Map<string, number>();
60	  for (const item of items) {
61	    if (isComponent(item)) {
62	      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
63	    } else {
64	      groups.push({
65	        base: MAIN_ITEM_BASE_PREMIUM[item.type],
66	        cursed: item.cursed === true,
67	        enchantment: item.enchantment ?? 0,
68	      });
69	    }
70	  }
71	  for (const count of componentCounts.values()) {
72	    groups.push({ base: componentBundleBase(count), cursed: false, enchantment: 0 });
73	  }
74	  return groups;
75	};
76	
77	const groupPremium = ({ base, cursed, enchantment }: BillingGroup): number => {
78	  const curseSurcharge = cursed ? base * CURSE_SURCHARGE_RATE : 0;
79	  const enchantmentSurcharge =
80	    enchantment >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
81	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
82	  return base + curseSurcharge + enchantmentSurcharge + firstInsuranceSurcharge;
83	};
84	
85	const sumGroupPremiums = (groups: BillingGroup[]): number =>
86	  groups.reduce((sum, g) => sum + groupPremium(g), 0);
87	
88	const policyBaseOf = (groups: BillingGroup[]): number =>
89	  groups.reduce((sum, g) => sum + g.base, 0);
90	
91	const loyaltyDiscountOf = (policyBase: number, customer: Customer): number =>
92	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
93	
94	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
95	  const groups = billingGroups(items);
96	  const itemsTotal = sumGroupPremiums(groups);
97	  const policyBase = policyBaseOf(groups);
98	  const loyaltyDiscount = loyaltyDiscountOf(policyBase, customer);
99	  const followUpDiscount = isFollowUp ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
100	  return Math.ceil(itemsTotal - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
101	};
102	
103	type Policy = { items: Item[]; cap: number };
104	
105	const insuranceSumOf = (items: Item[]): number =>
106	  items.reduce((sum, item) => sum + ITEM_INSURANCE_VALUE[item.type], 0);
107	
108	const isHighlyEnchantedForPayout = (item: Item | undefined): boolean =>
109	  item !== undefined && (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD;
110	
111	const reimbursableAmount = (amount: number, item: Item | undefined): number =>
112	  isHighlyEnchantedForPayout(item) ? amount * HIGH_ENCHANTMENT_PAYOUT_RATE : amount;
113	
114	const damagePayout = (damage: Damage, item: Item | undefined): number =>
115	  Math.max(0, reimbursableAmount(damage.amount, item) - DEDUCTIBLE);
116	
117	const findInsuredItem = (policy: Policy, itemType: string): Item | undefined =>
118	  policy.items.find((i) => i.type === itemType);
119	
120	const incidentPayout = (policy: Policy, incident: Incident): number =>
121	  incident.damages.reduce(
122	    (sum, d) => sum + damagePayout(d, findInsuredItem(policy, d.itemType)),
123	    0,
124	  );
125	
126	const newPolicy = (items: Item[]): Policy => ({
127	  items,
128	  cap: insuranceSumOf(items) * CAP_MULTIPLIER,
129	});
130	
131	const settleClaim = (policy: Policy, incident: Incident): ClaimResult => {
132	  const payout = Math.floor(Math.min(incidentPayout(policy, incident), policy.cap));
133	  policy.cap -= payout;
134	  return { payout, remainingCap: policy.cap };
135	};
136	
137	export const runScenario = (scenario: Scenario): ScenarioResult => {
138	  const policies: Policy[] = [];
139	  const results = scenario.steps.map((step) => {
140	    if (step.op === "quote") {
141	      const isFollowUp = policies.length > 0;
142	      policies.push(newPolicy(step.items));
143	      return { premium: quotePremium(step.items, scenario.customer, isFollowUp) };
144	    }
145	    return settleClaim(policies[step.policy], step.incident);
146	  });
147	  return { results };
148	};
